const code = (msg.payload.code || '').toUpperCase();
const value = Number(msg.payload.value);
const source = msg.payload.source || 'unknown';

if (!code || isNaN(value)) {
    node.warn('Payload inválido: ' + JSON.stringify(msg.payload));
    return null;
}

node.context().set('pendingCode', code);
node.context().set('pendingValue', value);
node.context().set('pendingSource', source);

const bucket = env.get('INFLUXDB_BUCKET') || 'autis';
const hoy = new Date().toISOString().split('T')[0];

msg.query = `
from(bucket: "${bucket}")
  |> range(start: ${hoy}T00:00:00Z, stop: ${hoy}T23:59:59Z)
  |> filter(fn: (r) => r._measurement == "divisas")
  |> filter(fn: (r) => r.Codigo_moneda == "${code}")
  |> last()
`;

return msg;

const code = node.context().get('pendingCode');
const newValue = node.context().get('pendingValue');
const source = node.context().get('pendingSource');

let mediaActual = 0;
let numApis = 0;

// msg.payload viene del InfluxDB In como array de filas
if (Array.isArray(msg.payload) && msg.payload.length > 0) {
    const row = msg.payload[0];
    // InfluxDB In devuelve objeto con las columnas como keys
    mediaActual = Number(row.Valor_media ?? row._value ?? 0);
    numApis = parseInt(row.Num_apis ?? 0, 10);
}

// Media incremental: Mn = (Mn-1 * n + v) / (n + 1)
const nuevaMedia = (mediaActual * numApis + newValue) / (numApis + 1);
const nuevoNumApis = numApis + 1;

const hoy = new Date();
hoy.setUTCHours(0, 0, 0, 0); // Timestamp fijo 00:00 UTC para sobrescribir

node.warn(`[${source}] ${code}: media ${mediaActual.toFixed(6)} (n=${numApis}) + ${newValue} → ${nuevaMedia.toFixed(6)} (n=${nuevoNumApis})`);

msg.payload = [{
    measurement: 'divisas',
    tags: { Codigo_moneda: code },
    fields: {
        Valor_media: Number(nuevaMedia.toFixed(8)),
        Num_apis: { value: nuevoNumApis, type: 'integer' },
        Ultima_fuente: source
    },
    timestamp: hoy
}];

return msg;

const datosPrevios = {};

for (const row of msg.payload || []) {
    const codigo = row.Codigo_moneda;
    const field = row._field;
    const value = row._value;
    if (!codigo || isNaN(value)) continue;
    if (!datosPrevios[codigo]) datosPrevios[codigo] = {};
    datosPrevios[codigo][field] = value;
}

const apis = flow.get("apiData") || [];
const hoy = new Date().toISOString().split("T")[0];
const registros = {};

for (const api of apis) {
    const fecha = api.date || hoy;
    if (fecha !== hoy) continue;
    if (!registros[fecha]) registros[fecha] = {};
    for (const [codigo, valor] of Object.entries(api.rates || {})) {
        if (valor === null || valor === undefined || isNaN(valor)) continue;
        if (!registros[fecha][codigo]) registros[fecha][codigo] = [];
        registros[fecha][codigo].push(Number(valor));
    }
}

const points = [];

for (const [fecha, monedas] of Object.entries(registros)) {
    for (const [codigo, valores] of Object.entries(monedas)) {
        const sumaNueva = valores.reduce((a, v) => a + v, 0);
        const numNuevo = valores.length;
        const prev = datosPrevios[codigo];
        let mediaFinal, numFinal;

        if (prev?.Valor_media && prev?.Num_apis) {
            const sumaPrev = prev.Valor_media * prev.Num_apis;
            numFinal = prev.Num_apis + numNuevo;
            mediaFinal = (sumaPrev + sumaNueva) / numFinal;
        } else {
            mediaFinal = sumaNueva / numNuevo;
            numFinal = numNuevo;
        }

        points.push({
            measurement: "divisas",
            tags: { Codigo_moneda: codigo },
            fields: { Valor_media: mediaFinal, Num_apis: numFinal },
            timestamp: new Date(fecha + "T00:00:00Z").getTime()
        });
    }
}

msg.payload = points;
return msg;

const hoy = new Date().toISOString().split("T")[0];

flow.set("apiData", msg.payload);

msg.query = `
from(bucket: "${env.get('INFLUXDB_BUCKET')}")
  |> range(start: ${hoy}T00:00:00Z, stop: ${hoy}T23:59:59Z)
  |> filter(fn: (r) => r._measurement == "divisas")
  |> filter(fn: (r) => r._field == "Valor_media" or r._field == "Num_apis")
  |> last()
`;

return msg;

const fechaInicio = msg.payload;
const hoy = new Date().toLocaleDateString('sv-SE');
const fechas = [];
let cursor = new Date(fechaInicio);
const fin = new Date(hoy);
while (cursor <= fin) {
    fechas.push(cursor.toLocaleDateString('sv-SE'));
    cursor.setDate(cursor.getDate() + 1);
}
flow.set('fechas_pendientes', fechas);
flow.set('fecha_idx', 0);
flow.set('total_fechas', fechas.length);
node.warn('Procesando ' + fechas.length + ' días desde ' + fechaInicio + ' hasta ' + hoy);
msg.payload = fechas[0];
return msg;

const fecha = msg.payload;
flow.set('fecha_actual', fecha);

msg.fecha = fecha;
// Formato YYYYMMDD para AwesomeAPI
msg.fechaAwesome = fecha.replace(/-/g, '');
msg._origMsgId = msg._msgid;

return msg;

const fecha = flow.get('fecha_actual');

msg.topic = 'frankfurter_' + fecha;
msg.fecha = fecha;

msg.payload = {
    rates: msg.payload.rates || {},
    date: fecha
};

return msg;

const fecha = flow.get('fecha_actual');

msg.topic = 'fawaz_' + fecha;
msg.fecha = fecha;

msg.payload = {
    rates: msg.payload.eur || {},
    date: fecha
};

return msg;

const apis = msg.payload;
const mapaDivisas = {};
let fecha = null;

for (const apiTag in apis) {
    const apiData = apis[apiTag];
    if (!apiData || typeof apiData !== 'object') continue;
    if (!fecha && apiData.date) fecha = apiData.date;
    const tasas = apiData.rates || apiData;
    for (const [codigo, valor] of Object.entries(tasas)) {
        const codigoNorm = codigo.toUpperCase();
        if (typeof valor !== 'number') continue;
        if (!mapaDivisas[codigoNorm]) {
            mapaDivisas[codigoNorm] = { suma: 0, conteo: 0 };
        }
        mapaDivisas[codigoNorm].suma += valor;
        mapaDivisas[codigoNorm].conteo += 1;
    }
}

if (!fecha) {
    node.warn('Sin fecha, saltando...');
    return null;
}

const resultados = Object.keys(mapaDivisas).map(codigo => ({
    codigo: codigo,
    media: mapaDivisas[codigo].suma / mapaDivisas[codigo].conteo,
    fuentes: mapaDivisas[codigo].conteo, // Mantenemos fuentes
    num_apis: mapaDivisas[codigo].conteo, // Añadimos alias por seguridad
    fecha: fecha
}));

const idx = flow.get('fecha_idx') || 0;
const total = flow.get('total_fechas') || 0;
node.warn('[' + (idx + 1) + '/' + total + ']  ' + fecha + ' — ' + resultados.length + ' monedas');

msg.payload = resultados;
msg.fecha = fecha;

// Al final de Calc histórico, antes de return msg:
const resumen = resultados.reduce((acc, r) => {
    acc[r.fuentes] = (acc[r.fuentes] || 0) + 1;
    return acc;
}, {});
node.warn('[' + (idx+1) + '/' + total + '] ' + fecha 
    + ' — ' + resultados.length + ' monedas | fuentes: ' + JSON.stringify(resumen));

return msg;

const records = msg.payload || [];
const fecha = msg.fecha;

msg.payload = records.map(item => {
    // 1. Obtenemos el valor numérico
    const valorFuentes = item.fuentes !== undefined ? item.fuentes : (item.num_apis ?? 0);
    const numApis = parseInt(valorFuentes, 10) || 0;

    return {
        measurement: 'divisas',
        tags: {
            Codigo_moneda: item.codigo.toUpperCase()
        },
        fields: {
            Valor_media: Number(item.media.toFixed(6)),
            Num_apis: numApis // <-- Enviamos el número directamente
        },
        timestamp: new Date(fecha + 'T12:00:00Z')
    };
});
return msg;

const fechas = flow.get('fechas_pendientes') || [];
let idx = flow.get('fecha_idx') || 0;
idx += 1;

if (idx >= fechas.length) {
    node.warn('🎉 Histórico completado — ' + fechas.length + ' días procesados');
    return null;
}

flow.set('fecha_idx', idx);
msg.payload = fechas[idx];
return msg;

const fecha = msg.fecha;
let source = '';

if (msg.topic.startsWith('frankfurter')) source = 'frankfurter';
else if (msg.topic.startsWith('fawaz')) source = 'fawaz';
else if (msg.topic.startsWith('awesome')) source = 'awesome';

const bufferKey = 'buffer_' + msg._origMsgId;
let buffer = flow.get(bufferKey) || { _ts: Date.now() };

buffer[source] = msg.payload;
buffer._fecha = buffer._fecha || fecha;
flow.set(bufferKey, buffer);

const apisPresentes = ['frankfurter', 'fawaz', 'awesome'].filter(k => buffer[k]);
const apisFaltantes = ['frankfurter', 'fawaz', 'awesome'].filter(k => !buffer[k]);
const timedOut = (Date.now() - buffer._ts) > 15000; // 15 s

if (apisPresentes.length < 3 && !timedOut) {
    return null; // Aún esperando, y no han pasado 15 s
}

// Llegamos aquí: tenemos las 3 APIs, o ha vencido el timeout
if (apisFaltantes.length > 0) {
    node.warn('⚠️ Timeout — APIs ausentes para ' + buffer._fecha + ': ' + apisFaltantes.join(', '));
}

flow.set(bufferKey, null);

msg.fecha = buffer._fecha;
msg.payload = {
    frankfurter: buffer.frankfurter || {},
    fawaz: buffer.fawaz || {},
    awesome: buffer.awesome || {}
};
return msg;

const fecha = flow.get('fecha_actual');

msg.topic = 'awesome_' + fecha;
msg.fecha = fecha;

const rates = {};

if (typeof msg.payload === 'object' && msg.payload !== null) {
    for (const pair in msg.payload) {
        const item = msg.payload[pair];

        if (!item) continue;

        const code = item.codein;
        const bid = parseFloat(item.bid);

        if (code && !isNaN(bid)) {
            rates[code.toUpperCase()] = bid;
        }
    }
}

node.warn(
    `AwesomeAPI (${fecha}) → ${Object.keys(rates).length} monedas: ${Object.keys(rates).join(', ')}`
);

msg.payload = {
    rates,
    date: fecha
};

return msg;

msg.topic = "frankfurter";
msg.payload = {
    rates: msg.payload.rates || {},
    date: msg.payload.date || new Date().toISOString().split("T")[0]
};
return msg;

msg.topic = "currency";
const data = msg.payload.eur;
const normalizedRates = {};

for (const [key, value] of Object.entries(data)) {

    normalizedRates[key.toUpperCase()] = value;
}

msg.payload = {
    rates: normalizedRates,
    date: msg.payload.date
};

return msg;

msg.topic = "fxapp";
msg.payload = {
    rates: msg.payload.rates || {},
    date: msg.payload.date || new Date().toISOString().split("T")[0]
};
return msg;

msg.topic = "awesome";
const rates = {};

for (const pair in msg.payload) {
    const code = pair.substring(3); 
    rates[code] = parseFloat(msg.payload[pair].bid);
}

msg.payload = {
    rates: rates,
    date: new Date().toISOString().split("T")[0]
};
return msg;
